/**
 * Standards/instructions context loaders (once:true skill hooks)
 *
 * Inject stable instructions once per skill invocation so agent prompts
 * stay lean. CC 2.1.72 prompt cache benefits from fewer repeated tokens.
 */

import { existsSync, readFileSync } from 'node:fs';
import { join } from 'node:path';
import type { HookInput, HookResult , HookContext} from '../types.js';
import { outputSilentSuccess, outputWithContext, getProjectDir } from '../lib/common.js';
import { readPackageJson } from './context-loader-utils.js';

/**
 * Implement Standards Loader — detects project framework stack.
 * Used by: implement skill (PreToolUse/Agent, once:true)
 *
 * Scans package.json, pyproject.toml, tsconfig.json to build a
 * framework standards summary injected once before agent spawning.
 */
export function implementStandardsLoader(_input: HookInput, hookCtx?: HookContext): HookResult {
  const projectDir = hookCtx?.projectDir ?? getProjectDir();
  const standards: string[] = [];

  // Node/TypeScript detection
  const pkg = readPackageJson(projectDir);
  if (pkg) {
    const allDeps = {
      ...(pkg.dependencies as Record<string, string> || {}),
      ...(pkg.devDependencies as Record<string, string> || {}),
    };

    // Frontend frameworks
    if (allDeps.next) standards.push(`Next.js ${allDeps.next}`);
    else if (allDeps.react) standards.push(`React ${allDeps.react}`);
    if (allDeps.vue) standards.push(`Vue ${allDeps.vue}`);

    // Backend frameworks (Node)
    if (allDeps.express) standards.push(`Express ${allDeps.express}`);
    if (allDeps.fastify) standards.push(`Fastify ${allDeps.fastify}`);

    // ORMs and data
    if (allDeps.prisma || allDeps['@prisma/client']) standards.push('Prisma ORM');
    if (allDeps.drizzle || allDeps['drizzle-orm']) standards.push('Drizzle ORM');

    // Validation
    if (allDeps.zod) standards.push('Zod validation');

    // TypeScript
    if (allDeps.typescript || existsSync(join(projectDir, 'tsconfig.json'))) {
      standards.push('TypeScript');
    }

    // Test frameworks
    if (allDeps.vitest) standards.push('vitest');
    else if (allDeps.jest) standards.push('jest');
    if (allDeps.playwright) standards.push('Playwright');
  }

  // Python detection
  const pyprojectPath = join(projectDir, 'pyproject.toml');
  if (existsSync(pyprojectPath)) {
    try {
      const content = readFileSync(pyprojectPath, 'utf-8');
      if (content.includes('fastapi')) standards.push('FastAPI');
      if (content.includes('django')) standards.push('Django');
      if (content.includes('flask')) standards.push('Flask');
      if (content.includes('sqlalchemy')) standards.push('SQLAlchemy');
      if (content.includes('pydantic')) standards.push('Pydantic');
      if (content.includes('pytest')) standards.push('pytest');
      if (content.includes('alembic')) standards.push('Alembic migrations');
    } catch { /* ignore read errors */ }
  }

  // Go detection
  if (existsSync(join(projectDir, 'go.mod'))) standards.push('Go');

  // Rust detection
  if (existsSync(join(projectDir, 'Cargo.toml'))) standards.push('Rust');

  if (!standards.length) return outputSilentSuccess();

  const ctx = [
    '[Project Standards — loaded once]',
    `Stack: ${standards.join(', ')}`,
    'All agents should follow these framework conventions.',
  ].join('\n');

  return outputWithContext(ctx);
}

/**
 * Review Dimensions Loader — injects review scoring dimensions.
 * Used by: review-pr skill (PreToolUse/Agent, once:true)
 *
 * Static content: review dimensions and output contract so each
 * review agent doesn't need them repeated in its prompt.
 */
export function reviewDimensionsLoader(_input: HookInput, hookCtx?: HookContext): HookResult {
  const ctx = [
    '[Review Dimensions — loaded once]',
    'Score each dimension 0-10:',
    '  1. Correctness: Logic bugs, edge cases, error handling',
    '  2. Security: OWASP Top 10, input validation, auth/authz',
    '  3. Performance: N+1 queries, unnecessary renders, memory leaks',
    '  4. Maintainability: Naming, complexity, DRY, single responsibility',
    '  5. Test coverage: Missing tests, edge cases, integration gaps',
    '  6. API design: Consistency, versioning, error responses',
    'Output: JSON { dimension, score, findings[], suggestions[] }',
  ].join('\n');

  return outputWithContext(ctx);
}

